const input = $input.first().json;
const webhookData = $('Webhook').first().json.body;
const prompt = webhookData.prompt;
const filePaths = webhookData.filePaths || [];
const jobId = webhookData.jobId;
const secrets = webhookData._secrets || {};
const promptMeta = webhookData.promptMeta || {};

function normalizePresentationSettings(ps) {
  const mv = ps && typeof ps === 'object' ? ps : {};

  const design = mv.design && typeof mv.design === 'object' ? mv.design : {};
  const palette = Array.isArray(design.palette) ? design.palette : [];
  const outPalette = palette
    .filter((x) => x && typeof x === 'object')
    .map((x) => ({
      hex: typeof x.hex === 'string' ? x.hex : null,
      role: typeof x.role === 'string' ? x.role : null,
    }))
    .filter((x) => x.hex && x.role);

  const legacyPalette = [];
  if (typeof mv.backgroundColor === 'string') legacyPalette.push({ hex: mv.backgroundColor, role: 'bg_primary' });
  if (typeof mv.primaryColor === 'string') legacyPalette.push({ hex: mv.primaryColor, role: 'accent_primary' });

  const mergedPalette = outPalette.length >= 2 ? outPalette : legacyPalette;

  const styleTags = Array.isArray(design.styleTags) ? design.styleTags.filter((t) => typeof t === 'string') : [];
  const customDesignPrompt = typeof design.customDesignPrompt === 'string' ? design.customDesignPrompt.trim() : '';

  const textDesign = mv.textDesign && typeof mv.textDesign === 'object' ? mv.textDesign : {};
  const styles = Array.isArray(textDesign.styles) ? textDesign.styles : [];

  const legacyFont = typeof mv.fontFamily === 'string' ? mv.fontFamily : null;
  const legacyTitleFont = typeof mv.titleFontFamily === 'string' ? mv.titleFontFamily : legacyFont;
  const legacySize = Number.isFinite(Number(mv.fontSize)) ? Number(mv.fontSize) : null;

  const normalizedStyles = styles
    .filter((s) => s && typeof s === 'object')
    .map((s, idx) => ({
      id: typeof s.id === 'string' ? s.id : `style_${idx + 1}`,
      name: typeof s.name === 'string' ? s.name : `Стиль ${idx + 1}`,
      applyTo: Array.isArray(s.applyTo) ? s.applyTo.filter((x) => typeof x === 'string') : [],
      colorHex: typeof s.colorHex === 'string' ? s.colorHex : null,
      fontFamily: typeof s.fontFamily === 'string' ? s.fontFamily : null,
      fontWeight: Number.isFinite(Number(s.fontWeight)) ? Number(s.fontWeight) : null,
      fontStyle: s.fontStyle === 'italic' ? 'italic' : 'normal',
      fontSizePt: Number.isFinite(Number(s.fontSizePt)) ? Number(s.fontSizePt) : null,
    }));

  const fallbackStyles = [];
  if (legacyTitleFont || legacySize) {
    fallbackStyles.push({
      id: 'titles',
      name: 'Заголовки',
      applyTo: ['titles'],
      colorHex: typeof mv.primaryColor === 'string' ? mv.primaryColor : '#2563eb',
      fontFamily: legacyTitleFont || 'Inter',
      fontWeight: 700,
      fontStyle: 'normal',
      fontSizePt: Math.max(32, Math.min(72, (legacySize || 16) * 3)),
    });
  }
  if (legacyFont || legacySize) {
    fallbackStyles.push({
      id: 'body',
      name: 'Основной текст',
      applyTo: ['body'],
      colorHex: '#111827',
      fontFamily: legacyFont || 'Inter',
      fontWeight: 400,
      fontStyle: 'normal',
      fontSizePt: Math.max(18, Math.min(40, (legacySize || 16) * 1.75)),
    });
  }

  return {
    palette: mergedPalette,
    styleTags,
    customDesignPrompt,
    textStyles: normalizedStyles.length >= 2 ? normalizedStyles : fallbackStyles,
    raw: mv,
  };
}

function tagHints(tag) {
  switch (tag) {
    case 'airy':
      return 'Airy: more whitespace, lower density, generous padding, fewer elements per slide.';
    case 'minimalistic':
      return 'Minimalistic: clean grid, minimal decoration, simple shapes, restrained palette usage.';
    case 'corporate':
      return 'Corporate: professional, consistent, conservative, clear hierarchy, subtle accents.';
    case 'playful':
      return 'Playful: friendly shapes, mild decoration, soft shadows, but still readable.';
    case 'bold_contrast':
      return 'Bold contrast: strong hierarchy, high contrast, decisive accent usage.';
    case 'editorial':
      return 'Editorial: typography-driven, magazine-like layout, strong rhythm and spacing.';
    case 'tech_futuristic':
      return 'Tech/futuristic: subtle neon accents, gradients sparingly, modern UI feel.';
    case 'dark_mode':
      return 'Dark: prefer dark backgrounds with light text; ensure contrast.';
    default:
      return null;
  }
}

function buildDesignBrief(ps) {
  const n = normalizePresentationSettings(ps);
  const lines = [];

  lines.push('DESIGN_BRIEF:');
  lines.push('PresentationDesign:');

  if (Array.isArray(n.palette) && n.palette.length > 0) {
    lines.push('- Palette (2..5 colors with roles):');
    for (const c of n.palette.slice(0, 5)) {
      lines.push(`  - ${c.hex} => ${c.role}`);
    }
  }

  if (Array.isArray(n.styleTags) && n.styleTags.length > 0) {
    lines.push('- Style tags (combine all): ' + n.styleTags.join(', '));
    for (const t of n.styleTags) {
      const h = tagHints(t);
      if (h) lines.push('  - ' + h);
    }
  }

  if (n.customDesignPrompt) {
    lines.push('- Custom design prompt: ' + n.customDesignPrompt);
  }

  lines.push('TextDesign:');
  if (Array.isArray(n.textStyles) && n.textStyles.length > 0) {
    lines.push('- Text styles (2..5):');
    for (const s of n.textStyles.slice(0, 5)) {
      const apply = Array.isArray(s.applyTo) && s.applyTo.length > 0 ? s.applyTo.join(', ') : '(not specified)';
      lines.push(`  - ${s.name} [applyTo: ${apply}]`);
      lines.push(`    color: ${s.colorHex || '(not set)'}`);
      lines.push(`    font: ${s.fontFamily || '(not set)'} weight=${s.fontWeight || '(not set)'} style=${s.fontStyle || 'normal'} size=${s.fontSizePt || '(not set)'}pt`);
    }
  }

  lines.push('Rules:');
  lines.push('- Follow DESIGN_BRIEF strictly when generating theme.css and per-slide CSS.');
  lines.push('- Map palette roles to CSS variables when possible:');
  lines.push('  bg_primary=>--bg, bg_alt=>--bg-alt, accent_primary=>--primary, accent_secondary=>--accent, text_primary=>--text, border_divider=>--text-muted/highlight borders, highlight=>--accent/highlight elements.');
  lines.push('- Ensure readable contrast between background and text.');
  lines.push('- Add required fonts to theme.fonts (Google Fonts) based on chosen text styles.');
  lines.push('- Palette MUST be visible (avoid bland minimalism):');
  lines.push('  - Every slide MUST use at least 2 palette roles (e.g., bg/bg_alt + an accent).');
  lines.push('  - Accent colors MUST appear on every slide via shapes/lines/badges/icons (not only tiny details).');
  lines.push('  - Use bg_alt for cards/sections on at least ~50% of slides.');
  lines.push('  - Use accent_secondary for secondary highlights, charts, icons, or gradient stops.');
  lines.push('- Each slide MUST include at least one design component: .accent-line, .tag/.tag-outline, .card/.card-bordered, .divider, .icon-circle, or background shape/gradient.');
  lines.push('- For tech_futuristic tag:');
  lines.push('  - Use subtle gradients on cover + section divider slides (accent_primary→accent_secondary at low intensity).');
  lines.push('  - Add small futuristic details: glow accent line, soft blur, dotted grid, or neon edge (subtle).');
  lines.push('- For corporate tag:');
  lines.push('  - Keep layout clean, but still use visible accents: accent lines, badges, structured cards.');
  lines.push('- Avoid: plain white background with plain black text across most slides.');
  lines.push('- If text colors are pure black (#000000) but palette has accents, you may still use accent colors for headings, badges, and highlights while keeping body text readable.');

  lines.push('DesignDataJSON (normalized, reference only):');
  lines.push(JSON.stringify({ design: { palette: n.palette || [], styleTags: n.styleTags || [], customDesignPrompt: n.customDesignPrompt || '' }, textDesign: { styles: n.textStyles || [] } }, null, 2));

  return lines.join('\n');
}

let systemPrompt = promptMeta.systemPrompt;
if (!systemPrompt || typeof systemPrompt !== 'string' || !systemPrompt.trim()) {
  systemPrompt = 'You are an expert presentation designer. You create visually stunning HTML/CSS slides rendered at 1920×1080 px.\n\nOUTPUT FORMAT — return ONLY valid JSON (no markdown, no code fences):\n{\n  "theme": {\n    "css": ":root { --primary: #2563eb; --font-heading: \'Inter\', sans-serif; }",\n    "fonts": ["Inter"]\n  },\n  "slides": [\n    {\n      "html": "<div class=\'centered\'><h1 class=\'heading-xl\'>Title</h1></div>",\n      "css": "",\n      "notes": "Speaker notes (optional)"\n    }\n  ]\n}\n\nIMPORTANT DESIGN INPUT:\n- If the user message contains a DESIGN_BRIEF block, you MUST follow it.\n- Use DESIGN_BRIEF to choose palette roles, typography styles, and to override CSS variables in theme.css.\n\nREFINEMENT MODE:\n- Sometimes you will receive an existing slide_data JSON and a user request to update it.\n- In refinement mode, you MUST return the COMPLETE updated slide_data JSON (all slides, full theme), not a diff.\n\nCSS FRAMEWORK — each slide is a <div class="slide"> (1920×1080, padding 80px). You have these utilities:\n\nVariables (override in theme.css): --primary, --primary-light, --primary-dark, --bg, --bg-alt, --text, --text-light, --text-muted, --accent, --success, --danger, --font-heading, --font-body, --font-mono.\n\nLayouts: .centered (flex center), .top-title (title + flex body), .split-2 / .split-3 (grid columns), .split-left-wide / .split-right-wide (2:1 / 1:2 grid).\n\nTypography: .heading-xl (72px bold), .heading-lg (52px), .heading-md (40px), .heading-sm (32px), .subtitle (32px light), .body-text (28px), .body-lg (32px), .caption (20px), .small (18px), .bold, .semibold, .uppercase.\n\nComponents: .card (bg-alt rounded box), .card-bordered, .card-primary (primary bg white text), .accent-line (80px colored bar), .divider, .tag (primary pill), .tag-outline, .icon-circle / .icon-circle-lg (round icon container), .number-big (96px stat), .quote (left-bordered italic), .code-block (dark mono block).\n\nLists: .bullets (styled ul), .bullets-lg, .numbered (auto-numbered circles).\n\nTables: .table (styled with colored header, striped rows).\n\nCharts: .bar-container + .bar (horizontal bars), .stat-value (64px number) + .stat-label.\n\nBackgrounds: .bg-primary, .bg-dark, .bg-gradient, .bg-gradient-light, .bg-alt. Dark backgrounds auto-adjust text and bullet colors.\n\nSpacing: .mt-1..mt-4 (16–64px), .mb-1..mb-3, .gap-1..gap-4, .p-1..p-3, .w-full, .h-full.\n\nImages: .img-contain, .img-cover, .img-rounded.\n\nDESIGN RULES:\n- Slide HTML goes INSIDE the .slide container (wrapper added automatically)\n- Use framework classes + custom inline styles or per-slide CSS for unique effects\n- Use Google Fonts via theme.fonts array (loaded automatically)\n- Prefer gradients, shadows, icons (Unicode emoji or SVG), visual hierarchy\n- Do NOT use JavaScript\n- Do NOT set width/height on the slide itself\n- First slide should be a title/cover slide\n- Use 5–10 slides for a typical presentation\n- If images are provided, reference them in HTML with src=\"attachment:ATTACHMENT_ID\" (we will replace it with a real data URL).\n- Use .img-contain for logos/icons, .img-cover for full-slide backgrounds, .img-rounded for rounded corners.\n- Respond in the same language as the user\'s prompt\n- Make content professional, concise, and visually polished';
}

const slideCount = Number(promptMeta.slideCount) || 0;
const slidePrompts = Array.isArray(promptMeta.slidePrompts) ? promptMeta.slidePrompts : [];
const presentationSettings = promptMeta.presentationSettings || {};
const fileAttachments = Array.isArray(promptMeta.fileAttachments) ? promptMeta.fileAttachments : [];

const designBrief = Object.keys(presentationSettings || {}).length > 0 ? buildDesignBrief(presentationSettings) : '';

let userMessage = '';

if (promptMeta.refinementMode) {
  userMessage += 'REFINEMENT MODE: You are updating an existing presentation.\n';
  userMessage += 'Return the COMPLETE updated slide_data JSON with all slides.\n\n';
  userMessage += 'Current slide_data:\n' + JSON.stringify(promptMeta.previousSlideData || {}, null, 2) + '\n\n';
  userMessage += 'User request:\n' + String(promptMeta.userMessage || '').trim();

  if (designBrief) {
    userMessage += '\n\n' + designBrief;
  }
} else {
  userMessage = prompt;

  if (slideCount > 0) {
    userMessage += `\n\nDesired slide count: ${slideCount}`;
  }

  if (slidePrompts.length > 0) {
    userMessage += '\n\nSlide-specific prompts:';
    for (const sp of slidePrompts) {
      userMessage += `\n- Slide ${sp.slideIndex + 1}: ${sp.prompt}`;
    }
  }

  if (designBrief) {
    userMessage += '\n\n' + designBrief;
  } else if (Object.keys(presentationSettings).length > 0) {
    userMessage += '\n\nPresentation theme settings (legacy):\n';
    userMessage += JSON.stringify(presentationSettings, null, 2);
  }

  if (fileAttachments.length > 0) {
    userMessage += '\n\nUploaded files:';
    for (const f of fileAttachments) {
      const kind = f.base64 ? 'IMAGE' : 'DOCUMENT';
      const pr = f.prompt ? ` — "${String(f.prompt).slice(0, 400)}"` : '';
      const ref = f.base64 && f.attachmentId ? ` (use in HTML as src=\"attachment:${f.attachmentId}\")` : '';
      userMessage += `\n- ${f.name} [${kind}]${pr}${ref}`;
    }
  } else if (filePaths.length > 0) {
    userMessage += '\n\nAvailable files:\n' + filePaths.map(f => '- ' + f).join('\n');
  }
}

const userContent = [{ type: 'text', text: userMessage }];
for (const f of fileAttachments) {
  if (f && f.base64 && f.mimeType) {
    userContent.push({ type: 'image_url', image_url: { url: `data:${f.mimeType};base64,${f.base64}` } });
  }
}

return [{ json: { systemPrompt, userMessage, userContent, jobId, secrets, promptMeta, filePaths } }];

const input = $input.first().json;
const jobId = $('Build LLM Prompt').first().json.jobId;
const secrets = $('Build LLM Prompt').first().json.secrets;

let content = '';
try {
  content = input.choices[0].message.content;
} catch(e) {
  content = JSON.stringify(input);
}

if (content.includes('```')) {
  content = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
}

let slideData;
try {
  slideData = JSON.parse(content);
  if (!slideData.slides || !Array.isArray(slideData.slides)) {
    throw new Error('Missing slides array');
  }
  for (let i = 0; i < slideData.slides.length; i++) {
    if (!slideData.slides[i].html || typeof slideData.slides[i].html !== 'string') {
      throw new Error(`Slide ${i} missing html field`);
    }
  }
} catch (e) {
  slideData = {
    theme: { css: ':root { --primary: #dc2626; }' },
    slides: [{
      html: '<div class="centered"><h1 class="heading-xl">Error</h1><p class="subtitle">' + (e.message || 'Failed to parse LLM response').replace(/</g, '&lt;') + '</p></div>',
      css: '',
      notes: ''
    }]
  };
}

return [{ json: { slideData, jobId, secrets } }];

const errorData = $input.first().json;
let errorMessage = 'Unknown error occurred in pipeline';
let jobId = null;
let internalApiKey = null;

try {
  if (errorData.execution && errorData.execution.error) {
    errorMessage = errorData.execution.error.message || errorMessage;
  }
} catch (e) {}

try {
  const runData = errorData.execution.data.resultData.runData;
  if (runData['Webhook']) {
    const webhookOutput = runData['Webhook'][0].data.main[0][0].json.body;
    jobId = webhookOutput.jobId;
    internalApiKey = webhookOutput._secrets ? webhookOutput._secrets.internalApiKey : null;
  }
} catch (e) {}

if (!jobId) {
  try {
    const runData = errorData.execution.data.resultData.runData;
    if (runData['Build LLM Prompt']) {
      const bld = runData['Build LLM Prompt'][0].data.main[0][0].json;
      jobId = bld.jobId;
      internalApiKey = bld.secrets ? bld.secrets.internalApiKey : null;
    }
  } catch (e) {}
}

return [{ json: { jobId, errorMessage, internalApiKey } }];
